base_css:
/* Base Resets */
    body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h); 
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }

    .font-syne { font-family: 'Syne', sans-serif; }

    /* ========================================================================== */
    /* COMPONENTS & TYPOGRAPHY                                                    */
    /* ========================================================================== */
    .section-title {
      position: relative; padding-bottom: .75rem; margin-bottom: 2rem;
      font-weight: 800; color: var(--primary-d); font-family: 'Syne', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.2rem);
    }
    .section-title::after {
      content: ''; position: absolute; bottom: 0; left: 0;
      width: 60px; height: 4px; border-radius: 2px;
      background: linear-gradient(90deg, var(--primary), var(--gold));
    }
    .section-title.center::after { left: 50%; transform: translateX(-50%); }

    .btn-primary-custom {
      display: inline-flex; align-items: center; justify-content: center; gap: 8px; 
      background: var(--primary); color: #fff; font-weight: 700; font-size: .95rem; 
      padding: 12px 28px; border-radius: 50px; border: none; 
      transition: all var(--t); box-shadow: 0 4px 12px rgba(0,102,255,0.2);
      text-decoration: none;
    }
    .btn-primary-custom:hover {
      background: var(--primary-2); transform: translateY(-2px); color: #fff;
      box-shadow: 0 6px 16px rgba(0,102,255,0.3);
    }

    .hover-lift { transition: transform 0.3s var(--ease), box-shadow 0.3s var(--ease), border-color 0.3s; }
    .hover-lift:hover { transform: translateY(-6px); box-shadow: var(--sh-md); border-color: rgba(51,133,255,0.15); z-index: 2; }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring {
      position: absolute; border-radius: 50%; border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff; 
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p {
      font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0;
    }

    /* ========================================================================== */
    /* STATS ROW                                                                  */
    /* ========================================================================== */
    .stats-section { margin-top: -50px; position: relative; z-index: 10; padding-bottom: 40px; }
    .stat-box {
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-md); 
      padding: 30px 20px; text-align: center; box-shadow: var(--sh-sm);
    }
    .stat-num { font-family: 'Syne', sans-serif; font-size: 2.2rem; font-weight: 800; color: var(--primary); line-height: 1; }
    .stat-lbl { font-size: .75rem; font-weight: 800; color: var(--text-m); margin-top: 8px; text-transform: uppercase; letter-spacing: .05em; }

    /* ========================================================================== */
    /* RECRUITMENT STEPS                                                          */
    /* ========================================================================== */
    .steps-grid { 
      display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 24px; 
    }
    .step-card {
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-md);
      padding: 36px 24px 24px; position: relative; box-shadow: var(--sh-xs);
      transition: transform var(--t), box-shadow var(--t);
    }
    .step-card:hover { transform: translateY(-4px); box-shadow: var(--sh-md); }
    .step-num {
      position: absolute; top: -18px; left: 24px;
      width: 40px; height: 40px; background: var(--primary); color: #fff;
      font-family: 'Syne', sans-serif; font-weight: 800; font-size: 1.1rem;
      border-radius: 50%; display: flex; align-items: center; justify-content: center;
      box-shadow: 0 4px 12px rgba(0,102,255,0.25);
    }
    .step-card h4 { font-size: 1.1rem; font-weight: 800; color: var(--primary-d); margin-bottom: 12px; font-family: 'Syne', sans-serif;}
    .step-card p { font-size: .9rem; color: var(--text-s); margin: 0; line-height: 1.6; }

    /* ========================================================================== */
    /* COMPANY GRID                                                               */
    /* ========================================================================== */
    .co-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
      gap: 24px;
      margin-top: 40px;
    }
    .co-card {
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-lg);
      padding: 32px 20px; text-align: center; cursor: pointer;
      display: flex; flex-direction: column; align-items: center; justify-content: center;
      transition: transform var(--t), box-shadow var(--t), border-color var(--t);
    }
    .co-card:hover { transform: translateY(-8px); box-shadow: var(--sh-md); border-color: var(--primary-l); }

    .co-icon {
      width: 80px; height: 80px; border-radius: 20px; background: var(--sur-2);
      display: flex; align-items: center; justify-content: center;
      font-size: 2.8rem; margin-bottom: 18px; border: 1px solid var(--bdr-s);
      transition: transform var(--t);
    }
    .co-card:hover .co-icon { transform: scale(1.1) rotate(5deg); background: var(--primary-xl); }

    .co-name { font-size: 1.2rem; font-weight: 800; color: var(--primary-d); margin-bottom: 6px; font-family: 'Syne', sans-serif;}
    .co-sector { font-size: .75rem; font-weight: 700; color: var(--text-m); text-transform: uppercase; letter-spacing: 0.05em; }

    /* ========================================================================== */
    /* CELL INFO & CONTACT                                                        */
    /* ========================================================================== */
    .cell-box {
      background: linear-gradient(135deg, var(--digital-blue-900) 0%, var(--digital-blue-800) 100%);
      border-radius: var(--r-xl); padding: 48px 40px; color: #fff;
      box-shadow: var(--sh-lg); position: relative; overflow: hidden;
    }
    .cell-box::before {
      content: ''; position: absolute; inset: 0;
      background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.03'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
    }
    .cell-box h2 { font-family: 'Syne', sans-serif; font-size: clamp(1.8rem, 4vw, 2.4rem); font-weight: 800; margin-bottom: 20px; }
    .cell-box p { color: rgba(255,255,255,0.8); font-size: 1.05rem; line-height: 1.7; margin-bottom: 32px; max-width: 800px; }

    .tpo-card {
      background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.15);
      border-radius: var(--r-lg); padding: 32px; backdrop-filter: blur(8px);
      display: flex; align-items: center; gap: 24px;
    }
    .tpo-avatar { width: 80px; height: 80px; border-radius: 50%; border: 3px solid var(--gold); flex-shrink: 0; }
    .tpo-info h4 { font-size: 1.2rem; font-weight: 800; margin-bottom: 4px; }
    .tpo-info div { font-size: .85rem; color: rgba(255,255,255,0.6); text-transform: uppercase; font-weight: 700; letter-spacing: 0.05em; margin-bottom: 12px; }
    .tpo-contact { display: flex; gap: 20px; flex-wrap: wrap; }
    .tpo-contact a { color: #fff; font-weight: 700; display: flex; align-items: center; gap: 8px; font-size: .95rem; }
    .tpo-contact a:hover { color: var(--gold); }

    /* ========================================================================== */
    /* SPLIT-LAYOUT MODAL                                                         */
    /* ========================================================================== */
    .modal-overlay {
      display: none;
      position: fixed; inset: 0;
      background: rgba(0,14,36,0.65);
      z-index: 10000;
      align-items: center; justify-content: center;
      padding: 20px;
      backdrop-filter: blur(6px);
    }
    .modal-overlay.open { display: flex; }

    .modal-box {
      width: 860px; max-width: 100%;
      background: #fff;
      border-radius: 24px;
      overflow: hidden;
      box-shadow: 0 24px 60px rgba(0,0,0,0.2);
      animation: modalPop 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      display: flex;
      flex-direction: row;
      position: relative;
    }
    @keyframes modalPop {
      from { transform: scale(0.92); opacity: 0; }
      to { transform: scale(1); opacity: 1; }
    }

    .m-left {
      width: 40%;
      position: relative;
      display: flex; align-items: center; justify-content: center;
      background: linear-gradient(135deg, var(--digital-blue-100), var(--digital-blue-50));
      border-right: 1px solid var(--bdr-s);
      padding: 40px; font-size: 7rem;
    }
    .m-right { 
      width: 60%;
      padding: 48px 40px; 
      background: #fff; 
      overflow-y: auto;
      max-height: 85vh;
      position: relative;
    }

    .m-close {
      position: absolute; top: 20px; right: 20px;
      width: 36px; height: 36px; border-radius: 50%;
      background: var(--sur-2); color: var(--text-s); 
      border: 1px solid var(--bdr);
      display: flex; align-items: center; justify-content: center;
      cursor: pointer; font-size: 1.1rem; z-index: 10;
      transition: all 0.2s;
    }
    .m-close:hover { background: var(--error); color: #fff; border-color: var(--error); transform: rotate(90deg); }

    .m-name-title {
      font-size: 1.8rem; font-weight: 800; color: var(--primary-d);
      margin: 0 0 4px 0; line-height: 1.2; font-family: 'DM Sans', sans-serif;
    }
    .m-sector-tag {
      display: inline-block; background: var(--primary-xl); color: var(--primary);
      padding: 6px 16px; border-radius: 50px; font-size: 0.8rem; font-weight: 800;
      border: 1px solid var(--primary-l); margin-bottom: 32px;
      text-transform: uppercase; letter-spacing: 0.05em;
    }

    .m-list { list-style: none; padding: 0; margin: 0; }
    .m-list li {
      display: flex; align-items: flex-start; gap: 16px;
      padding: 16px 0; border-bottom: 1px solid var(--bdr-s);
    }
    .m-list li:last-child { border-bottom: none; padding-bottom: 0; }

    .m-icon-sq {
      width: 44px; height: 44px; border-radius: 12px;
      background: var(--digital-blue-50); color: var(--digital-blue-600);
      display: flex; align-items: center; justify-content: center;
      font-size: 1.2rem; flex-shrink: 0; border: 1px solid rgba(0,102,255,0.05);
    }
    .m-info-block { display: flex; flex-direction: column; gap: 2px; }
    .m-label-sm {
      font-size: 0.7rem; font-weight: 800; letter-spacing: 0.08em;
      text-transform: uppercase; color: var(--text-m);
    }
    .m-val-text { font-size: 1rem; font-weight: 700; color: var(--primary-d); line-height: 1.4; }

    @media (max-width: 768px) {
      .modal-box { flex-direction: column; width: 92%; }
      .m-left { width: 100%; min-height: 200px; padding: 30px; border-right: none; border-bottom: 1px solid var(--bdr-s); font-size: 4rem; }
      .m-right { width: 100%; padding: 32px 24px; }
      .m-close { top: 16px; right: 16px; background: rgba(255,255,255,0.9); border-color: transparent; }
      .m-name-title { font-size: 1.5rem; }
      .tpo-card { flex-direction: column; text-align: center; }
      .tpo-contact { justify-content: center; }
    }

    /* ========================================================================== */
    /* ANIMATIONS (Scroll Reveal)                                                 */
    /* ========================================================================== */
    .fade-up { opacity: 0; transform: translateY(32px); transition: opacity .6s var(--ease), transform .6s var(--ease); }
    .fade-up.visible { opacity: 1; transform: translateY(0); }
    .fade-in { opacity: 0; transition: opacity .6s var(--ease); }
    .fade-in.visible { opacity: 1; }

    .delay-1 { transition-delay: .05s; }
    .delay-2 { transition-delay: .1s; }
    .delay-3 { transition-delay: .15s; }
    .delay-4 { transition-delay: .2s; }
    .delay-5 { transition-delay: .25s; }

